/**
 * Cursor Catalog
 *
 * Custom cursor types — all gated on @media (pointer: fine).
 * Never applied on touch/coarse devices. CSS and JS generated by
 * generators/cursor-engine.ts.
 *
 * Catalog entries describe WHAT each cursor is and WHEN it applies.
 * No CSS or JS strings here.
 */
export const CURSOR_CATALOG = [
    {
        type: "none",
        description: "No custom cursor — browser default. Low entropy or physics:none genomes.",
        forbiddenFor: {},
        usesMagneticAttr: false,
    },
    {
        type: "dot_circle",
        description: "4px dot (instant) + 24px circle (lerp 0.12) — two-layer follower.",
        forbiddenFor: {
            maxEntropy: 0.15,
        },
        usesMagneticAttr: false,
    },
    {
        type: "crosshair_precision",
        description: "Thin 1px cross, expands on interactive elements — precision feel.",
        forbiddenFor: {
            philosophies: ["chaotic", "expressive"],
        },
        usesMagneticAttr: false,
    },
    {
        type: "magnetic_blob",
        description: "Organic SVG blob that morphs on hover — requires spring or magnetic physics.",
        forbiddenFor: {
            requiresPhysics: ["spring", "magnetic"],
            philosophies: ["minimalist", "swiss_grid", "technical"],
        },
        usesMagneticAttr: true,
        magneticRange: 80,
    },
    {
        type: "color_inverter",
        description: "Circle with mix-blend-mode:difference — inverts whatever is underneath.",
        forbiddenFor: {
            minEntropy: 0.35,
        },
        usesMagneticAttr: false,
    },
    {
        type: "context_text",
        description: "Shows text label (DRAG, VIEW, OPEN) per element type — contextual clarity.",
        forbiddenFor: {
            philosophies: ["minimalist", "swiss_grid"],
            minEntropy: 0.30,
        },
        usesMagneticAttr: false,
    },
    {
        type: "expanding_fill",
        description: "Cursor grows to fill button/link bounding box — tactile expansion.",
        forbiddenFor: {
            requiresPhysicsNot: ["none"],
        },
        usesMagneticAttr: false,
    },
    {
        type: "trail_echo",
        description: "5–8 trailing dots follow cursor with exponential decay.",
        forbiddenFor: {
            minEntropy: 0.50,
            philosophies: ["minimalist", "swiss_grid", "technical"],
        },
        usesMagneticAttr: false,
    },
    {
        type: "magnetic_pull",
        description: "Interactive elements attract cursor ±12px translate on pointermove.",
        forbiddenFor: {
            requiresPhysics: ["spring", "magnetic"],
            requiresPhysicsNot: ["none"],
        },
        usesMagneticAttr: true,
        magneticRange: 60,
    },
];
// ── Selector ──────────────────────────────────────────────────────────────────
export function getCursorEntry(type) {
    return CURSOR_CATALOG.find(c => c.type === type) ?? CURSOR_CATALOG[0];
}
/**
 * Select the cursor type for a genome given its constraints.
 * Returns "none" when no custom cursor is appropriate.
 */
export function selectCursorType(opts) {
    const { philosophy, entropy, physics } = opts;
    // entropy < 0.20 → no custom cursor
    if (entropy < 0.20)
        return "none";
    // physics:none → no custom cursor (no animation system to drive it)
    if (physics === "none")
        return "none";
    // Build eligible list (exclusion gates)
    const eligible = CURSOR_CATALOG.filter(entry => {
        if (entry.type === "none")
            return false;
        const f = entry.forbiddenFor;
        if (f.philosophies?.includes(philosophy))
            return false;
        if (f.requiresPhysics && !f.requiresPhysics.includes(physics))
            return false;
        if (f.requiresPhysicsNot?.includes(physics))
            return false;
        if (f.maxEntropy !== undefined && entropy > f.maxEntropy)
            return false;
        if (f.minEntropy !== undefined && entropy < f.minEntropy)
            return false;
        return true;
    });
    if (eligible.length === 0)
        return "none";
    // Priority: magnetic types for magnetic/spring physics
    if (physics === "magnetic" || physics === "spring") {
        const magnetic = eligible.find(e => e.type === "magnetic_blob" || e.type === "magnetic_pull");
        if (magnetic)
            return magnetic.type;
    }
    // High entropy → prefer expressive types
    if (entropy > 0.70) {
        const expressive = eligible.find(e => e.type === "trail_echo" || e.type === "color_inverter");
        if (expressive)
            return expressive.type;
    }
    // Default: dot_circle (clean, works everywhere)
    return eligible.find(e => e.type === "dot_circle")?.type ?? eligible[0].type;
}
